var displayTable = function(orders) {
    const foodSet = new Set();
    const tableSet = new Set();
    const counts = {};
    for (const [, tbl, food] of orders) {
        foodSet.add(food);
        tableSet.add(Number(tbl));
        if (!counts[tbl]) counts[tbl] = {};
        counts[tbl][food] = (counts[tbl][food] || 0) + 1;
    }
    const foods = [...foodSet].sort();
    const tables = [...tableSet].sort((a, b) => a - b);
    const result = [['Table', ...foods]];
    for (const t of tables) {
        const row = [String(t), ...foods.map(f => String(counts[t] && counts[t][f] ? counts[t][f] : 0))];
        result.push(row);
    }
    return result;
};
